import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.CNG7EpJN.js";const u=JSON.parse('{"title":"注文管理（ハンディPOS）","description":"","frontmatter":{"title":"注文管理（ハンディPOS）"},"headers":[],"relativePath":"tenant/06-orders.md","filePath":"tenant/06-orders.md"}'),l={name:"tenant/06-orders.md"};function o(i,t,h,b,c,n){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_6-注文管理-ハンディpos" tabindex="-1">6. 注文管理（ハンディPOS） <a class="header-anchor" href="#_6-注文管理-ハンディpos" aria-label="Permalink to &quot;6. 注文管理（ハンディPOS）&quot;">​</a></h1><p>この章では、ホールスタッフが使う <strong>ハンディPOS</strong> の操作を、来店から注文、配膳、呼び出し、会計待ち、席移動、取消、未送信復旧までまとめて説明します。</p><p>ハンディは「注文を入れる画面」だけではありません。現在のPOSLAでは、ホールが見るべき <strong>今やること</strong> を集約する運用ボードも兼ねています。壁掛け端末として置く場合も、同じハンディ画面を使います。</p><div class="tip custom-block"><p class="custom-block-title">先に結論</p><p>通常運用でスタッフの手数を増やさないため、ハンディの基本操作は次の考え方で使います。</p><ol><li>お客様が来店したら、テーブルを確認してQRを開放する</li><li>セルフ注文なら、お客様がQRから注文する</li><li>スタッフが注文を取る場合だけ、ハンディの店内注文から入力する</li><li>KDSで料理完成になったら、運用タブで配膳する</li><li>呼び出し、会計待ち、清掃待ち、時間超過は運用タブで上から処理する</li><li>間違いが起きたときだけ、取消・戻し・席移動・未送信復旧を使う</li></ol></div><h2 id="_6-1-ハンディで扱う業務範囲" tabindex="-1">6-1. ハンディで扱う業務範囲 <a class="header-anchor" href="#_6-1-ハンディで扱う業務範囲" aria-label="Permalink to &quot;6-1. ハンディで扱う業務範囲&quot;">​</a></h2><table tabindex="0"><thead><tr><th>業務</th><th>ハンディで行うこと</th><th>主なタブ</th></tr></thead><tbody><tr><td>来店受付</td><td>空席確認、着席、QR開放、予約着席</td><td>テーブル状況、予約、運用</td></tr><tr><td>セルフ注文開始</td><td>QR開放、開放取消、再発行、残り時間確認</td><td>テーブル状況、運用</td></tr><tr><td>スタッフ注文</td><td>テーブル選択、商品選択、数量・オプション・メモ入力、送信</td><td>店内注文</td></tr><tr><td>テイクアウト</td><td>顧客名、電話番号、受取時間、商品入力、送信</td><td>テイクアウト</td></tr><tr><td>配膳</td><td>KDSの料理完成通知を確認し、配膳完了にする</td><td>運用</td></tr><tr><td>呼び出し対応</td><td>客席呼び出し、厨房呼び出し、対応済み</td><td>運用</td></tr><tr><td>会計待ち</td><td>会計待ちにする、間違い時に食事中へ戻す</td><td>テーブル状況、運用</td></tr><tr><td>清掃待ち</td><td>会計後の清掃待ち確認、清掃完了</td><td>運用、テーブル状況</td></tr><tr><td>席移動</td><td>卓Aから卓Bへセッション・注文・QR・メモ・呼び出しを移す</td><td>テーブル状況、運用</td></tr><tr><td>注文修正</td><td>注文取消、品目取消、数量変更、配膳取消</td><td>注文履歴、運用</td></tr><tr><td>通信失敗復旧</td><td>未送信注文の中身確認、再送、破棄</td><td>ヘッダー、運用</td></tr></tbody></table><h2 id="_6-2-画面構成" tabindex="-1">6-2. 画面構成 <a class="header-anchor" href="#_6-2-画面構成" aria-label="Permalink to &quot;6-2. 画面構成&quot;">​</a></h2><h3 id="_6-2-1-ヘッダー" tabindex="-1">6-2-1. ヘッダー <a class="header-anchor" href="#_6-2-1-ヘッダー" aria-label="Permalink to &quot;6-2-1. ヘッダー&quot;">​</a></h3><table tabindex="0"><thead><tr><th>表示</th><th>説明</th></tr></thead><tbody><tr><td>ハンディ</td><td>画面名</td></tr><tr><td>店舗名</td><td>現在操作している店舗</td></tr><tr><td>店舗切替</td><td>複数店舗に所属している場合に表示</td></tr><tr><td>ハンディ / 壁掛け / レジ横</td><td>端末モード切替</td></tr><tr><td>音ON / 音OFF</td><td>運用通知音のON/OFF</td></tr><tr><td>未送信</td><td>通信失敗で端末内に残っている注文件数</td></tr><tr><td>ユーザー名</td><td>ログイン中のデバイスアカウント</td></tr><tr><td>ログアウト</td><td>端末入替・紛失対応・アカウント変更時に使う（日次閉店では通常使わない）</td></tr></tbody></table><h3 id="_6-2-2-端末モード" tabindex="-1">6-2-2. 端末モード <a class="header-anchor" href="#_6-2-2-端末モード" aria-label="Permalink to &quot;6-2-2. 端末モード&quot;">​</a></h3><p>端末モードは、同じハンディ画面をどこに置くかで表示密度を変えるための切替です。</p><table tabindex="0"><thead><tr><th>モード</th><th>用途</th><th>表示の特徴</th></tr></thead><tbody><tr><td>ハンディ</td><td>スタッフが持ち歩くスマホ/小型端末</td><td>通常密度。注文入力、卓操作、履歴確認をすべて使う</td></tr><tr><td>壁掛け</td><td>ホール共有のタブレット/モニタ</td><td>文字大きめ。呼び出し、料理完成、会計待ち、清掃待ちを優先</td></tr><tr><td>レジ横</td><td>レジ付近で会計待ちや清掃待ちを見る端末</td><td>会計・清掃に寄せた表示。卓の補助操作は少なめ</td></tr></tbody></table><p>端末モードは端末ごとに保存されます。別のスマホで切り替えても、今使っている端末の表示設定だけが変わります。</p><h3 id="_6-2-3-通知音" tabindex="-1">6-2-3. 通知音 <a class="header-anchor" href="#_6-2-3-通知音" aria-label="Permalink to &quot;6-2-3. 通知音&quot;">​</a></h3><p><code>音ON</code> にすると、運用タブで未対応の通知があるときに音が鳴ります。</p><table tabindex="0"><thead><tr><th>項目</th><th>仕様</th></tr></thead><tbody><tr><td>初期値</td><td>OFF</td></tr><tr><td>ONにする場所</td><td>ヘッダーの <code>音OFF</code> ボタン</td></tr><tr><td>対象</td><td>呼び出し、料理完成、会計待ち放置、清掃待ち放置、時間超過</td></tr><tr><td>再通知</td><td>未対応のまま残ると約3分ごと</td></tr><tr><td>強調通知</td><td>呼び出し3分超、料理完成5分超などは強めの音</td></tr><tr><td>保存単位</td><td>端末ごと</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">通知音が初期OFFの理由</p><p>ChromeやSafariなどのブラウザでは、ユーザーが画面を一度操作するまで自動で音を鳴らせません。そのため、壁掛け端末では開店時に一度だけ <code>音OFF</code> を押して <code>音ON</code> にしてください。</p></div><h2 id="_6-3-タブごとの役割" tabindex="-1">6-3. タブごとの役割 <a class="header-anchor" href="#_6-3-タブごとの役割" aria-label="Permalink to &quot;6-3. タブごとの役割&quot;">​</a></h2><h3 id="_6-3-1-店内注文" tabindex="-1">6-3-1. 店内注文 <a class="header-anchor" href="#_6-3-1-店内注文" aria-label="Permalink to &quot;6-3-1. 店内注文&quot;">​</a></h3><p>店内席のお客様からスタッフが注文を取るときに使います。</p><table tabindex="0"><thead><tr><th>表示</th><th>説明</th></tr></thead><tbody><tr><td>テーブル選択</td><td>注文を入れる卓を選ぶ</td></tr><tr><td>選択卓パネル</td><td>卓の状態、経過時間、注文数、会計待ち、QR開放中などを表示</td></tr><tr><td>卓クイック操作</td><td>注文、会計呼び出し、会計解除、メモ、人数、席移動など</td></tr><tr><td>よく出る</td><td>最近よく出ている商品をワンタップで追加</td></tr><tr><td>この卓の直近</td><td>同じ卓の直近注文を再注文</td></tr><tr><td>カテゴリ</td><td>定食、ドリンクなどの商品分類</td></tr><tr><td>商品グリッド</td><td>商品をタップしてカートへ入れる</td></tr><tr><td>カート</td><td>数量変更、メモ、送信</td></tr></tbody></table><h3 id="_6-3-2-テイクアウト" tabindex="-1">6-3-2. テイクアウト <a class="header-anchor" href="#_6-3-2-テイクアウト" aria-label="Permalink to &quot;6-3-2. テイクアウト&quot;">​</a></h3><p>店頭や電話で受けたテイクアウト注文をスタッフが入力します。</p><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td>顧客名</td><td>受け渡し時に確認する名前</td></tr><tr><td>電話番号</td><td>連絡が必要な場合に使う</td></tr><tr><td>受取時間</td><td>KDSとレジで確認する受取予定時刻</td></tr><tr><td>商品</td><td>テイクアウトする商品</td></tr></tbody></table><h3 id="_6-3-3-テーブル状況" tabindex="-1">6-3-3. テーブル状況 <a class="header-anchor" href="#_6-3-3-テーブル状況" aria-label="Permalink to &quot;6-3-3. テーブル状況&quot;">​</a></h3><p>全卓の状態を確認し、来店受付や卓操作を行います。</p><table tabindex="0"><thead><tr><th>状態</th><th>意味</th><th>主な操作</th></tr></thead><tbody><tr><td>空き</td><td>まだ使用していない卓</td><td>着席、QR開放</td></tr><tr><td>QR開放中</td><td>スタッフがQRを開放し、お客様の読込待ち</td><td>QR取消、QR再発行</td></tr><tr><td>着席</td><td>セッションはあるが、注文がまだ少ない状態</td><td>注文、QR表示、メモ、人数、席移動</td></tr><tr><td>未注文</td><td>着席後まだ注文が入っていない</td><td>注文確認、声かけ</td></tr><tr><td>食事中</td><td>注文があり、通常利用中</td><td>注文、会計呼び出し、QR表示</td></tr><tr><td>会計待ち</td><td>お客様が会計へ進む状態</td><td>会計解除、レジ案内</td></tr><tr><td>時間超過</td><td>時間制限プランの残り時間を超過</td><td>声かけ、延長確認</td></tr><tr><td>清掃待ち</td><td>会計後、次の案内前に片付けが必要</td><td>清掃完了</td></tr></tbody></table><p>予約から着席した卓では、テーブルカードに予約情報も表示されます。表示される内容は、予約者名、人数、予約時刻、予約メモ、好み、アレルギー、注意点、来店回数などです。アレルギーや注意点がある場合は、注文入力や配膳前に必ず確認してください。</p><h3 id="_6-3-4-運用" tabindex="-1">6-3-4. 運用 <a class="header-anchor" href="#_6-3-4-運用" aria-label="Permalink to &quot;6-3-4. 運用&quot;">​</a></h3><p>運用タブは、ホールが見るべき <strong>今やること</strong> を集約します。上から順に処理すれば、重要な未対応が残りにくい構成です。</p><table tabindex="0"><thead><tr><th>表示</th><th>説明</th></tr></thead><tbody><tr><td>サマリーカード</td><td>未送信、QR開放中、料理完成、呼び出し、会計待ち、清掃待ち、時間超過、未注文の件数</td></tr><tr><td>KDS通知</td><td>客席呼び出し、厨房呼び出し、料理完成</td></tr><tr><td>次にやること</td><td>放置・未対応の卓を優先表示</td></tr><tr><td>端末ログ</td><td>どの端末で配膳完了、呼び出し対応済み、清掃完了などを行ったか</td></tr><tr><td>卓クイック操作</td><td>各卓の現在状態と操作ボタン</td></tr></tbody></table><h3 id="_6-3-5-予約" tabindex="-1">6-3-5. 予約 <a class="header-anchor" href="#_6-3-5-予約" aria-label="Permalink to &quot;6-3-5. 予約&quot;">​</a></h3><p>当日の予約を確認し、予約客のQR開放や即着席を行います。</p><table tabindex="0"><thead><tr><th>操作</th><th>説明</th></tr></thead><tbody><tr><td>空席確認</td><td>日付、時刻、人数から予約可能か確認</td></tr><tr><td>電話予約追加</td><td>名前、電話番号、人数、時刻、テーブル、メモを入力</td></tr><tr><td>QR開放</td><td>予約客が来店した卓をQR開放</td></tr><tr><td>即着席</td><td>予約客をスタッフ操作で着席済みにする</td></tr><tr><td>no-show</td><td>無断キャンセルとして記録</td></tr></tbody></table><p>予約一覧では、VIP、常連、アレルギー、遅刻・no-showなどのリスク、リマインド未対応がバッジで表示されます。詳細には、前回来店、来店回数、好み、注意点、アレルギー、予約メモが表示されるため、来店受付前に確認できます。</p><h3 id="_6-3-6-注文履歴" tabindex="-1">6-3-6. 注文履歴 <a class="header-anchor" href="#_6-3-6-注文履歴" aria-label="Permalink to &quot;6-3-6. 注文履歴&quot;">​</a></h3><p>本日の注文を確認し、必要に応じて修正します。</p><table tabindex="0"><thead><tr><th>操作</th><th>説明</th></tr></thead><tbody><tr><td>更新</td><td>最新の注文履歴を取得</td></tr><tr><td>修正</td><td>注文内容をカートへ戻して更新</td></tr><tr><td>注文取消</td><td>注文全体を取消</td></tr><tr><td>品目取消</td><td>1商品だけ取消</td></tr><tr><td>数量変更</td><td>品目単位で数量を増減</td></tr><tr><td>配膳取消</td><td>間違って配膳完了した品目を提供待ちへ戻す</td></tr></tbody></table><h2 id="_6-4-標準フロー1-来店後、お客様がセルフ注文する" tabindex="-1">6-4. 標準フロー1: 来店後、お客様がセルフ注文する <a class="header-anchor" href="#_6-4-標準フロー1-来店後、お客様がセルフ注文する" aria-label="Permalink to &quot;6-4. 標準フロー1: 来店後、お客様がセルフ注文する&quot;">​</a></h2><h3 id="_6-4-1-流れ" tabindex="-1">6-4-1. 流れ <a class="header-anchor" href="#_6-4-1-流れ" aria-label="Permalink to &quot;6-4-1. 流れ&quot;">​</a></h3><ol><li>お客様が来店</li><li>スタッフが空席を確認</li><li>卓へ案内</li><li>ハンディでQRを開放</li><li>お客様が卓のQRを読み込む</li><li>セルフメニューが開く</li><li>お客様が自分のスマホで注文</li><li>KDSに注文が表示</li><li>調理完了後、運用タブに料理完成通知</li><li>ホールが配膳</li><li>お客様が会計へ進む</li><li>会計完了後、セッションが終了し、同じURLでは注文できなくなる</li></ol><h3 id="_6-4-2-qrを開放する手順" tabindex="-1">6-4-2. QRを開放する手順 <a class="header-anchor" href="#_6-4-2-qrを開放する手順" aria-label="Permalink to &quot;6-4-2. QRを開放する手順&quot;">​</a></h3><ol><li>ハンディを開く</li><li><code>テーブル状況</code> タブをタップ</li><li>案内する卓を探す</li><li>卓が <code>空き</code> であることを確認</li><li><code>QR開放</code> をタップ</li><li>確認ダイアログで内容を確認</li><li>問題なければOK</li><li>卓の状態が <code>QR開放中</code> になる</li><li>運用タブにも <code>QR開放中</code> として表示される</li></ol><p>QR開放中に見える情報:</p><table tabindex="0"><thead><tr><th>表示</th><th>意味</th></tr></thead><tbody><tr><td>QR読込待ち</td><td>まだお客様がQRを読み込んでいない</td></tr><tr><td>残り○分</td><td>QR開放の有効期限までの残り時間</td></tr><tr><td>開放: 端末名</td><td>どのデバイスアカウントでQRを開放したか</td></tr></tbody></table><h3 id="_6-4-3-お客様への案内文" tabindex="-1">6-4-3. お客様への案内文 <a class="header-anchor" href="#_6-4-3-お客様への案内文" aria-label="Permalink to &quot;6-4-3. お客様への案内文&quot;">​</a></h3><p>スタッフは次のように案内します。</p><blockquote><p>こちらのQRコードをカメラで読み込んでください。メニューが開いたら、そのままご注文いただけます。</p></blockquote><p>高齢のお客様やスマホ操作に不慣れなお客様には、次のように補足します。</p><blockquote><p>カメラを起動して、このQRに向けてください。画面上に出たリンクを押すとメニューが開きます。</p></blockquote><h3 id="_6-4-4-qr開放を間違えた場合" tabindex="-1">6-4-4. QR開放を間違えた場合 <a class="header-anchor" href="#_6-4-4-qr開放を間違えた場合" aria-label="Permalink to &quot;6-4-4. QR開放を間違えた場合&quot;">​</a></h3><ol><li><code>運用</code> または <code>テーブル状況</code> を開く</li><li><code>QR開放中</code> の卓を探す</li><li><code>QR取消</code> をタップ</li><li>確認してOK</li><li>その卓は空き状態に戻る</li></ol><p>取消後、すでにお客様がそのQRを読み込んでいなければ、注文画面には進めません。</p><h3 id="_6-4-5-qrを再発行する場合" tabindex="-1">6-4-5. QRを再発行する場合 <a class="header-anchor" href="#_6-4-5-qrを再発行する場合" aria-label="Permalink to &quot;6-4-5. QRを再発行する場合&quot;">​</a></h3><table tabindex="0"><thead><tr><th>状況</th><th>操作</th></tr></thead><tbody><tr><td>開放したが時間切れになりそう</td><td>QR再発行</td></tr><tr><td>間違って古いQRを見せてしまった</td><td>QR再発行</td></tr><tr><td>お客様のスマホで読み込みがうまくいかない</td><td>QR再発行</td></tr></tbody></table><p><code>QR再発行</code> は、古い開放を取り消して新しい開放を作り直します。運用タブの残り時間も新しくなります。</p><h3 id="_6-4-6-会計後に同じurlを開いた場合" tabindex="-1">6-4-6. 会計後に同じURLを開いた場合 <a class="header-anchor" href="#_6-4-6-会計後に同じurlを開いた場合" aria-label="Permalink to &quot;6-4-6. 会計後に同じURLを開いた場合&quot;">​</a></h3><p>会計が完了すると、対象テーブルのセッションは終了します。</p><p>終了後は、前のお客様が持っていたURLやブラウザ履歴から同じページを開いても、注文・履歴・会計情報へ進めないように制御されます。次のお客様には、スタッフがあらためてQRを開放してから使ってもらいます。</p><div class="warning custom-block"><p class="custom-block-title">会計後に必ず確認すること</p><p>会計が終わったら、レジ側の会計完了だけでなく、テーブル状態が <code>清掃待ち</code> または終了済みになっていることを確認してください。前のお客様のセッションが残っていると、次のお客様の注文と混ざる原因になります。</p></div><h2 id="_6-5-標準フロー2-スタッフがハンディで注文を取る" tabindex="-1">6-5. 標準フロー2: スタッフがハンディで注文を取る <a class="header-anchor" href="#_6-5-標準フロー2-スタッフがハンディで注文を取る" aria-label="Permalink to &quot;6-5. 標準フロー2: スタッフがハンディで注文を取る&quot;">​</a></h2><h3 id="_6-5-1-注文入力の手順" tabindex="-1">6-5-1. 注文入力の手順 <a class="header-anchor" href="#_6-5-1-注文入力の手順" aria-label="Permalink to &quot;6-5-1. 注文入力の手順&quot;">​</a></h3><ol><li><code>店内注文</code> タブを開く</li><li><code>テーブル</code> から対象卓を選ぶ</li><li>選択卓パネルで卓番号と状態を確認</li><li>カテゴリを選ぶ</li><li>商品をタップ</li><li>オプションがある商品は、オプションを選んで <code>カートに追加</code></li><li>数量はカート内の <code>+</code> / <code>-</code> で調整</li><li>必要ならメモ欄に「ネギ抜き」「先出し」などを入力</li><li><code>注文送信</code> をタップ</li><li>成功メッセージを確認</li><li>KDSに注文が出たことを確認</li></ol><h3 id="_6-5-2-テーブル選択時に確認すること" tabindex="-1">6-5-2. テーブル選択時に確認すること <a class="header-anchor" href="#_6-5-2-テーブル選択時に確認すること" aria-label="Permalink to &quot;6-5-2. テーブル選択時に確認すること&quot;">​</a></h3><table tabindex="0"><thead><tr><th>確認項目</th><th>理由</th></tr></thead><tbody><tr><td>卓番号</td><td>別卓に注文を入れないため</td></tr><tr><td>状態</td><td>会計待ち、清掃待ち、QR開放中などでは通常注文しないため</td></tr><tr><td>経過時間</td><td>時間制限プランや長時間滞在の確認</td></tr><tr><td>注文数・合計金額</td><td>すでに注文済みか確認</td></tr><tr><td>メモ</td><td>アレルギー、VIP、子連れ、記念日などの注意を確認</td></tr><tr><td>会計待ち表示</td><td>追加注文を受ける前に会計解除が必要な場合がある</td></tr></tbody></table><h3 id="_6-5-3-よく出る・この卓の直近" tabindex="-1">6-5-3. よく出る・この卓の直近 <a class="header-anchor" href="#_6-5-3-よく出る・この卓の直近" aria-label="Permalink to &quot;6-5-3. よく出る・この卓の直近&quot;">​</a></h3><table tabindex="0"><thead><tr><th>表示</th><th>使い方</th></tr></thead><tbody><tr><td>よく出る</td><td>店舗で最近よく出ている商品をワンタップ追加</td></tr><tr><td>この卓の直近</td><td>同じ卓の直近注文を再度カートに追加</td></tr><tr><td>直近再注文</td><td>テーブル未選択時やテイクアウトで直近注文を再利用</td></tr></tbody></table><p>再注文後も、必ずカート内の商品・数量を確認してください。品切れ商品は追加できません。</p><h3 id="_6-5-4-注文メモ" tabindex="-1">6-5-4. 注文メモ <a class="header-anchor" href="#_6-5-4-注文メモ" aria-label="Permalink to &quot;6-5-4. 注文メモ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>入力例</th><th>用途</th></tr></thead><tbody><tr><td>ネギ抜き</td><td>調理指示</td></tr><tr><td>先にドリンク</td><td>提供順</td></tr><tr><td>アレルギー確認済み</td><td>安全確認</td></tr><tr><td>子ども用皿希望</td><td>サービス</td></tr><tr><td>誕生日</td><td>接客メモ</td></tr></tbody></table><p>メモは短く、厨房がすぐ読める内容にしてください。長文の接客メモはテーブルメモへ入れます。</p><h3 id="_6-5-5-会計待ち中の追加注文" tabindex="-1">6-5-5. 会計待ち中の追加注文 <a class="header-anchor" href="#_6-5-5-会計待ち中の追加注文" aria-label="Permalink to &quot;6-5-5. 会計待ち中の追加注文&quot;">​</a></h3><p>テーブルが <code>会計待ち</code> の場合、追加注文は通常受けません。POSLAでは、会計待ちの卓に対して <strong>セルフ追加注文は停止中</strong> と表示されます。</p><p>間違って会計待ちにした場合:</p><ol><li><code>運用</code> または <code>テーブル状況</code> を開く</li><li>対象卓の <code>会計解除</code> をタップ</li><li>確認してOK</li><li>卓が <code>食事中</code> に戻る</li><li>必要なら追加注文を入力</li></ol><p>会計待ちのまま追加注文を受けると、レジ側の合計確認とお客様の認識がずれる可能性があります。追加注文を受ける場合は、先に会計解除してから入力します。</p><h2 id="_6-6-標準フロー3-kdsから料理完成、配膳する" tabindex="-1">6-6. 標準フロー3: KDSから料理完成、配膳する <a class="header-anchor" href="#_6-6-標準フロー3-kdsから料理完成、配膳する" aria-label="Permalink to &quot;6-6. 標準フロー3: KDSから料理完成、配膳する&quot;">​</a></h2><h3 id="_6-6-1-kds側の流れ" tabindex="-1">6-6-1. KDS側の流れ <a class="header-anchor" href="#_6-6-1-kds側の流れ" aria-label="Permalink to &quot;6-6-1. KDS側の流れ&quot;">​</a></h3><ol><li>注文がKDSの <code>受付</code> に入る</li><li>厨房スタッフが <code>調理開始</code></li><li>調理が終わったら <code>完成</code></li><li>完成した商品がハンディの運用タブへ <code>料理完成</code> として表示される</li></ol><h3 id="_6-6-2-ホール側の配膳手順" tabindex="-1">6-6-2. ホール側の配膳手順 <a class="header-anchor" href="#_6-6-2-ホール側の配膳手順" aria-label="Permalink to &quot;6-6-2. ホール側の配膳手順&quot;">​</a></h3><ol><li>ハンディの <code>運用</code> タブを開く</li><li><code>料理完成</code> の件数を確認</li><li>KDS通知欄で卓番号と商品名を見る</li><li>商品を取りに行く</li><li>卓へ配膳</li><li>ハンディで <code>配膳完了</code> をタップ</li><li>端末ログに、どの端末で配膳完了したか残る</li></ol><h3 id="_6-6-3-1タップ運用の考え方" tabindex="-1">6-6-3. 1タップ運用の考え方 <a class="header-anchor" href="#_6-6-3-1タップ運用の考え方" aria-label="Permalink to &quot;6-6-3. 1タップ運用の考え方&quot;">​</a></h3><p>ハンディはデバイスアカウントでログインする前提です。人の担当者を都度選ばせると、現場の操作が増えてしまいます。そのため、通常業務では <code>対応開始</code> を挟まず、料理を運んだ後に <code>配膳完了</code> を1回押して完了します。</p><table tabindex="0"><thead><tr><th>操作</th><th>通常の扱い</th></tr></thead><tbody><tr><td>料理完成</td><td>配膳後に <code>配膳完了</code></td></tr><tr><td>客席呼び出し</td><td>用件対応後に <code>対応済み</code></td></tr><tr><td>厨房呼び出し</td><td>用件確認後に <code>対応済み</code></td></tr><tr><td>清掃待ち</td><td>清掃後に <code>清掃完了</code></td></tr></tbody></table><p>誰が行ったかではなく、<strong>未対応が残っていないか</strong> を優先します。人の確認が必要な運用は、口頭や店舗ルールで補い、ハンディでは作業消込を最短にします。</p><h3 id="_6-6-4-配膳完了を間違えた場合" tabindex="-1">6-6-4. 配膳完了を間違えた場合 <a class="header-anchor" href="#_6-6-4-配膳完了を間違えた場合" aria-label="Permalink to &quot;6-6-4. 配膳完了を間違えた場合&quot;">​</a></h3><p>方法1: 運用タブの端末ログから戻す</p><ol><li><code>運用</code> タブを開く</li><li><code>端末ログ</code> を見る</li><li>直近の <code>配膳完了</code> を探す</li><li><code>配膳取消</code> をタップ</li><li>対象商品が <code>提供待ち</code> に戻る</li></ol><p>方法2: 注文履歴から戻す</p><ol><li><code>注文履歴</code> タブを開く</li><li>対象注文を探す</li><li>対象品目の <code>配膳取消</code> をタップ</li><li>対象商品が <code>提供待ち</code> に戻る</li></ol><h2 id="_6-7-標準フロー4-お客様から呼び出し" tabindex="-1">6-7. 標準フロー4: お客様から呼び出し <a class="header-anchor" href="#_6-7-標準フロー4-お客様から呼び出し" aria-label="Permalink to &quot;6-7. 標準フロー4: お客様から呼び出し&quot;">​</a></h2><h3 id="_6-7-1-呼び出しの種類" tabindex="-1">6-7-1. 呼び出しの種類 <a class="header-anchor" href="#_6-7-1-呼び出しの種類" aria-label="Permalink to &quot;6-7-1. 呼び出しの種類&quot;">​</a></h3><table tabindex="0"><thead><tr><th>種類</th><th>発生元</th><th>運用タブの表示</th></tr></thead><tbody><tr><td>客席呼び出し</td><td>お客様のセルフメニュー</td><td>客席呼出</td></tr><tr><td>厨房呼び出し</td><td>KDS</td><td>厨房呼出</td></tr><tr><td>料理完成</td><td>KDSの完成操作</td><td>料理完成</td></tr></tbody></table><h3 id="_6-7-2-呼び出し対応手順" tabindex="-1">6-7-2. 呼び出し対応手順 <a class="header-anchor" href="#_6-7-2-呼び出し対応手順" aria-label="Permalink to &quot;6-7-2. 呼び出し対応手順&quot;">​</a></h3><ol><li><code>運用</code> タブを開く</li><li><code>呼び出し</code> 件数を見る</li><li>KDS通知欄で卓番号と内容を見る</li><li>卓へ向かう</li><li>用件を確認</li><li>対応が終わったら <code>対応済み</code> をタップ</li><li>端末ログに、どの端末で対応済みにしたか残る</li></ol><h3 id="_6-7-3-放置時の強調" tabindex="-1">6-7-3. 放置時の強調 <a class="header-anchor" href="#_6-7-3-放置時の強調" aria-label="Permalink to &quot;6-7-3. 放置時の強調&quot;">​</a></h3><table tabindex="0"><thead><tr><th>対象</th><th>強調される目安</th></tr></thead><tbody><tr><td>客席呼び出し</td><td>約3分</td></tr><tr><td>厨房呼び出し</td><td>約3分</td></tr><tr><td>料理完成</td><td>約5分</td></tr><tr><td>会計待ち</td><td>約5分</td></tr><tr><td>清掃待ち</td><td>約10分</td></tr><tr><td>時間超過</td><td>表示された時点で要確認</td></tr></tbody></table><p>壁掛け端末で <code>音ON</code> にしている場合、未対応が残ると約3分ごとに再通知されます。</p><h2 id="_6-8-運用タブの詳しい見方" tabindex="-1">6-8. 運用タブの詳しい見方 <a class="header-anchor" href="#_6-8-運用タブの詳しい見方" aria-label="Permalink to &quot;6-8. 運用タブの詳しい見方&quot;">​</a></h2><h3 id="_6-8-1-サマリーカード" tabindex="-1">6-8-1. サマリーカード <a class="header-anchor" href="#_6-8-1-サマリーカード" aria-label="Permalink to &quot;6-8-1. サマリーカード&quot;">​</a></h3><table tabindex="0"><thead><tr><th>カード</th><th>意味</th><th>タップ時</th></tr></thead><tbody><tr><td>未送信</td><td>端末内に残っている未送信注文</td><td>未送信注文モーダルを開く</td></tr><tr><td>QR開放中</td><td>QRを開放したが、まだ読まれていない卓</td><td>卓カードで取消/再発行</td></tr><tr><td>料理完成</td><td>KDSで完成した料理</td><td>KDS通知欄で配膳</td></tr><tr><td>呼び出し</td><td>客席/厨房からの呼び出し</td><td>KDS通知欄で対応</td></tr><tr><td>会計待ち</td><td>会計へ案内する卓</td><td>卓操作へ移動</td></tr><tr><td>清掃待ち</td><td>会計後、片付け待ち</td><td>清掃完了</td></tr><tr><td>時間超過</td><td>時間制限を超えた卓</td><td>声かけ</td></tr><tr><td>未注文</td><td>着席後まだ注文がない卓</td><td>注文確認、声かけ</td></tr></tbody></table><h3 id="_6-8-2-次にやること" tabindex="-1">6-8-2. 次にやること <a class="header-anchor" href="#_6-8-2-次にやること" aria-label="Permalink to &quot;6-8-2. 次にやること&quot;">​</a></h3><table tabindex="0"><thead><tr><th>表示</th><th>対応</th></tr></thead><tbody><tr><td>未送信注文を再送してください</td><td>未送信モーダルを開いて中身確認、再送または破棄</td></tr><tr><td>QR開放後の読込待ち</td><td>お客様がQRを読めているか確認。間違いならQR取消</td></tr><tr><td>会計待ちの卓をレジへ案内</td><td>レジへ案内。間違いなら会計解除</td></tr><tr><td>会計済みの卓を清掃</td><td>卓を片付け、清掃完了</td></tr><tr><td>時間超過の卓を確認</td><td>延長・ラストオーダー・退店案内を判断</td></tr><tr><td>着席後まだ注文がない卓</td><td>注文に困っていないか声かけ</td></tr></tbody></table><h3 id="_6-8-3-端末ログ" tabindex="-1">6-8-3. 端末ログ <a class="header-anchor" href="#_6-8-3-端末ログ" aria-label="Permalink to &quot;6-8-3. 端末ログ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>ログの意味</th></tr></thead><tbody><tr><td>配膳完了</td><td>どの端末で料理を提供済みにしたか</td></tr><tr><td>呼び出し対応済み</td><td>どの端末で呼び出しを完了したか</td></tr><tr><td>QR開放</td><td>どの端末でQRを開放したか</td></tr><tr><td>QR取消</td><td>どの端末でQR開放を取り消したか</td></tr><tr><td>会計待ち</td><td>どの端末で会計待ちにしたか</td></tr><tr><td>食事中へ戻し</td><td>どの端末で会計待ちを解除したか</td></tr><tr><td>席移動</td><td>どの卓からどの卓へ移動したか</td></tr><tr><td>注文取消</td><td>どの端末で注文を取り消したか</td></tr><tr><td>品目取消</td><td>どの端末で品目を取り消したか</td></tr><tr><td>数量変更</td><td>どの端末で数量を変更したか</td></tr><tr><td>配膳取消</td><td>どの端末で配膳完了を戻したか</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">監査の考え方</p><p>ハンディはデバイスアカウントで使うため、人の担当者までは判別しません。ハンディでは「どの端末で操作したか」と「未対応が残っていないか」を重視します。会計や現金移動など人の責任を明確にする必要がある操作は、レジ側のPIN入力で扱います。</p></div><h2 id="_6-9-卓クイック操作" tabindex="-1">6-9. 卓クイック操作 <a class="header-anchor" href="#_6-9-卓クイック操作" aria-label="Permalink to &quot;6-9. 卓クイック操作&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ボタン</th><th>表示される主な状態</th><th>操作内容</th></tr></thead><tbody><tr><td>注文</td><td>食事中、着席中</td><td>店内注文へ移動し、その卓を選択</td></tr><tr><td>着席</td><td>空き</td><td>スタッフ操作で着席セッションを作成</td></tr><tr><td>予約着席</td><td>予約ありの空席</td><td>予約客を着席済みにする</td></tr><tr><td>QR開放</td><td>空き</td><td>お客様がセルフ注文できるようにする</td></tr><tr><td>QR取消</td><td>QR開放中</td><td>誤開放を取り消す</td></tr><tr><td>QR再発行</td><td>QR開放中</td><td>古い開放を取り消して再度開放する</td></tr><tr><td>QR表示</td><td>着席中</td><td>追加QRや個別QRを表示</td></tr><tr><td>メモ</td><td>着席中</td><td>卓メモを編集</td></tr><tr><td>人数</td><td>着席中</td><td>人数を変更</td></tr><tr><td>席移動</td><td>着席中</td><td>卓Aから卓Bへ移動</td></tr><tr><td>会計呼び出し</td><td>食事中</td><td>会計待ちにする</td></tr><tr><td>会計解除</td><td>会計待ち</td><td>食事中へ戻す</td></tr><tr><td>清掃完了</td><td>清掃待ち</td><td>空席に戻す</td></tr></tbody></table><h2 id="_6-10-席移動" tabindex="-1">6-10. 席移動 <a class="header-anchor" href="#_6-10-席移動" aria-label="Permalink to &quot;6-10. 席移動&quot;">​</a></h2><h3 id="_6-10-1-席移動が必要な場面" tabindex="-1">6-10-1. 席移動が必要な場面 <a class="header-anchor" href="#_6-10-1-席移動が必要な場面" aria-label="Permalink to &quot;6-10-1. 席移動が必要な場面&quot;">​</a></h3><table tabindex="0"><thead><tr><th>場面</th><th>例</th></tr></thead><tbody><tr><td>予約席を空けたい</td><td>予約客が来るため、別卓へ移動</td></tr><tr><td>人数が増えた</td><td>2名席から4名席へ移動</td></tr><tr><td>眺めや設備の都合</td><td>お客様希望で席を変更</td></tr><tr><td>相席調整</td><td>大きな卓を空けたい</td></tr><tr><td>トラブル対応</td><td>空調、照明、騒音などで移動</td></tr></tbody></table><h3 id="_6-10-2-席移動の手順" tabindex="-1">6-10-2. 席移動の手順 <a class="header-anchor" href="#_6-10-2-席移動の手順" aria-label="Permalink to &quot;6-10-2. 席移動の手順&quot;">​</a></h3><ol><li><code>テーブル状況</code> または <code>運用</code> を開く</li><li>移動元の卓を探す</li><li><code>席移動</code> をタップ</li><li>移動先候補から空席を選ぶ</li><li><code>移動する</code> をタップ</li><li>成功メッセージを確認</li><li>移動元が空き、移動先にセッションが移ることを確認</li></ol><h3 id="_6-10-3-席移動で一緒に移るもの" tabindex="-1">6-10-3. 席移動で一緒に移るもの <a class="header-anchor" href="#_6-10-3-席移動で一緒に移るもの" aria-label="Permalink to &quot;6-10-3. 席移動で一緒に移るもの&quot;">​</a></h3><table tabindex="0"><thead><tr><th>対象</th><th>説明</th></tr></thead><tbody><tr><td>テーブルセッション</td><td>着席状態、開始時刻、人数、プラン、コース</td></tr><tr><td>未会計注文</td><td>会計前の注文</td></tr><tr><td>注文履歴のテーブル表示</td><td>注文が移動先卓として見える</td></tr><tr><td>QR関連</td><td>現在のセッションQR、次回開放中の情報</td></tr><tr><td>卓メモ</td><td>アレルギー、接客メモなど</td></tr><tr><td>呼び出し</td><td>客席呼び出し、料理完成通知など</td></tr><tr><td>サブセッション</td><td>相席/個別QRのグループ</td></tr></tbody></table><h3 id="_6-10-4-席移動できない場合" tabindex="-1">6-10-4. 席移動できない場合 <a class="header-anchor" href="#_6-10-4-席移動できない場合" aria-label="Permalink to &quot;6-10-4. 席移動できない場合&quot;">​</a></h3><table tabindex="0"><thead><tr><th>理由</th><th>対処</th></tr></thead><tbody><tr><td>移動先が使用中</td><td>別の空席を選ぶ</td></tr><tr><td>移動先がQR開放中</td><td>QR取消してから移動、または別卓を選ぶ</td></tr><tr><td>対象セッションがない</td><td>最新状態へ更新</td></tr><tr><td>通信エラー</td><td>Wi-Fi確認後に再操作</td></tr></tbody></table><h2 id="_6-11-注文取消・数量変更" tabindex="-1">6-11. 注文取消・数量変更 <a class="header-anchor" href="#_6-11-注文取消・数量変更" aria-label="Permalink to &quot;6-11. 注文取消・数量変更&quot;">​</a></h2><h3 id="_6-11-1-注文全体を取り消す" tabindex="-1">6-11-1. 注文全体を取り消す <a class="header-anchor" href="#_6-11-1-注文全体を取り消す" aria-label="Permalink to &quot;6-11-1. 注文全体を取り消す&quot;">​</a></h3><ol><li><code>注文履歴</code> を開く</li><li>対象注文を探す</li><li><code>注文取消</code> をタップ</li><li>取消理由を入力</li><li>OK</li><li>注文ステータスが取消になる</li><li>端末ログに残る</li></ol><table tabindex="0"><thead><tr><th>理由</th><th>使う場面</th></tr></thead><tbody><tr><td>卓間違い</td><td>別卓に入れてしまった</td></tr><tr><td>お客様キャンセル</td><td>注文直後に不要になった</td></tr><tr><td>重複送信</td><td>同じ注文を二重に入れた</td></tr><tr><td>品切れ</td><td>注文後に在庫切れが分かった</td></tr><tr><td>厨房判断</td><td>調理不可、提供不可</td></tr></tbody></table><h3 id="_6-11-2-品目単位で取り消す" tabindex="-1">6-11-2. 品目単位で取り消す <a class="header-anchor" href="#_6-11-2-品目単位で取り消す" aria-label="Permalink to &quot;6-11-2. 品目単位で取り消す&quot;">​</a></h3><ol><li><code>注文履歴</code> を開く</li><li>対象注文を開く</li><li>対象商品の <code>品目取消</code> をタップ</li><li>理由を入力</li><li>OK</li><li>その品目だけ取消になる</li><li>注文全体は残る</li></ol><h3 id="_6-11-3-数量を変更する" tabindex="-1">6-11-3. 数量を変更する <a class="header-anchor" href="#_6-11-3-数量を変更する" aria-label="Permalink to &quot;6-11-3. 数量を変更する&quot;">​</a></h3><ol><li><code>注文履歴</code> を開く</li><li>対象注文を探す</li><li>対象商品の <code>数量+</code> または <code>数量-</code> をタップ</li><li>調理中以降の場合は理由を入力</li><li>OK</li><li>数量が変更される</li></ol><div class="warning custom-block"><p class="custom-block-title">KDS送信後の変更</p><p>KDS送信後に取消・数量変更を行う場合は、厨房に口頭でも伝えてください。システム上は記録されますが、すでに調理に入っている商品は厨房の手元作業とズレる可能性があります。</p></div><h3 id="_6-11-4-取消・変更で残る情報" tabindex="-1">6-11-4. 取消・変更で残る情報 <a class="header-anchor" href="#_6-11-4-取消・変更で残る情報" aria-label="Permalink to &quot;6-11-4. 取消・変更で残る情報&quot;">​</a></h3><table tabindex="0"><thead><tr><th>情報</th><th>用途</th></tr></thead><tbody><tr><td>どの端末で操作したか</td><td>端末単位の確認、問い合わせ対応</td></tr><tr><td>いつ操作したか</td><td>問い合わせ、会計差異確認</td></tr><tr><td>何を変更したか</td><td>注文内容の追跡</td></tr><tr><td>理由</td><td>厨房・会計・店長確認</td></tr></tbody></table><h2 id="_6-12-未送信注文の復旧" tabindex="-1">6-12. 未送信注文の復旧 <a class="header-anchor" href="#_6-12-未送信注文の復旧" aria-label="Permalink to &quot;6-12. 未送信注文の復旧&quot;">​</a></h2><h3 id="_6-12-1-未送信注文とは" tabindex="-1">6-12-1. 未送信注文とは <a class="header-anchor" href="#_6-12-1-未送信注文とは" aria-label="Permalink to &quot;6-12-1. 未送信注文とは&quot;">​</a></h3><p>未送信注文は、ハンディで注文送信しようとしたが、通信障害や一時的なAPIエラーで送れなかった注文です。POSLAは注文内容を端末内に一時保存し、後で再送できるようにします。</p><p>未送信があると、ヘッダーに <code>未送信 1</code> のように件数が表示されます。運用タブのサマリーにも表示されます。</p><h3 id="_6-12-2-未送信注文の確認" tabindex="-1">6-12-2. 未送信注文の確認 <a class="header-anchor" href="#_6-12-2-未送信注文の確認" aria-label="Permalink to &quot;6-12-2. 未送信注文の確認&quot;">​</a></h3><ol><li>ヘッダーの <code>未送信</code> をタップ</li><li>未送信注文一覧が開く</li><li>卓番号またはテイクアウト名を確認</li><li>商品・数量・合計金額を確認</li><li>失敗理由と再送回数を確認</li></ol><h3 id="_6-12-3-再送する" tabindex="-1">6-12-3. 再送する <a class="header-anchor" href="#_6-12-3-再送する" aria-label="Permalink to &quot;6-12-3. 再送する&quot;">​</a></h3><ol><li>未送信注文の中身を確認</li><li>まだ必要な注文なら <code>再送信</code> をタップ</li><li>ボタンが <code>送信中</code> になる</li><li>成功すると一覧から消える</li><li>KDSに注文が出たことを確認</li></ol><h3 id="_6-12-4-破棄する" tabindex="-1">6-12-4. 破棄する <a class="header-anchor" href="#_6-12-4-破棄する" aria-label="Permalink to &quot;6-12-4. 破棄する&quot;">​</a></h3><ol><li>お客様がキャンセルした、または別端末で入れ直したことを確認</li><li><code>破棄</code> をタップ</li><li>確認してOK</li><li>未送信一覧から消える</li></ol><div class="warning custom-block"><p class="custom-block-title">二重送信に注意</p><p>未送信を再送する前に、KDSや注文履歴に同じ注文がすでに入っていないか確認してください。POSLAは二重送信防止用のキーを持っていますが、スタッフが別端末で同じ注文を手入力した場合は別注文として扱われます。</p></div><h2 id="_6-13-壁掛け端末として使う" tabindex="-1">6-13. 壁掛け端末として使う <a class="header-anchor" href="#_6-13-壁掛け端末として使う" aria-label="Permalink to &quot;6-13. 壁掛け端末として使う&quot;">​</a></h2><h3 id="_6-13-1-設置場所" tabindex="-1">6-13-1. 設置場所 <a class="header-anchor" href="#_6-13-1-設置場所" aria-label="Permalink to &quot;6-13-1. 設置場所&quot;">​</a></h3><table tabindex="0"><thead><tr><th>場所</th><th>理由</th></tr></thead><tbody><tr><td>ホール中央の壁</td><td>全員が見やすい</td></tr><tr><td>レジ横</td><td>会計待ち、清掃待ちに気づきやすい</td></tr><tr><td>厨房入口付近</td><td>料理完成と配膳の連携に使いやすい</td></tr></tbody></table><p>避ける場所:</p><table tabindex="0"><thead><tr><th>場所</th><th>理由</th></tr></thead><tbody><tr><td>客席から丸見えの位置</td><td>内部メモや端末ログが見える可能性</td></tr><tr><td>水がかかる場所</td><td>端末故障の原因</td></tr><tr><td>強い逆光</td><td>視認性が下がる</td></tr><tr><td>Wi-Fiが弱い場所</td><td>更新遅延が起きる</td></tr></tbody></table><h3 id="_6-13-2-開店時の設定" tabindex="-1">6-13-2. 開店時の設定 <a class="header-anchor" href="#_6-13-2-開店時の設定" aria-label="Permalink to &quot;6-13-2. 開店時の設定&quot;">​</a></h3><ol><li>ハンディを開く</li><li>ヘッダーの端末モードで <code>壁掛け</code> を選ぶ</li><li><code>運用</code> タブを開く</li><li>必要なら <code>音OFF</code> をタップして <code>音ON</code> にする</li><li>画面が見やすい角度に固定する</li><li>端末の省電力設定で画面スリープ時間を長めにする</li></ol><h3 id="_6-13-3-壁掛けで優先して見るもの" tabindex="-1">6-13-3. 壁掛けで優先して見るもの <a class="header-anchor" href="#_6-13-3-壁掛けで優先して見るもの" aria-label="Permalink to &quot;6-13-3. 壁掛けで優先して見るもの&quot;">​</a></h3><table tabindex="0"><thead><tr><th>優先度</th><th>表示</th><th>理由</th></tr></thead><tbody><tr><td>1</td><td>呼び出し</td><td>お客様を待たせない</td></tr><tr><td>2</td><td>料理完成</td><td>提供遅れを防ぐ</td></tr><tr><td>3</td><td>会計待ち</td><td>会計滞留を防ぐ</td></tr><tr><td>4</td><td>清掃待ち</td><td>次の案内を早くする</td></tr><tr><td>5</td><td>時間超過</td><td>声かけ漏れを防ぐ</td></tr><tr><td>6</td><td>未注文</td><td>注文に困っている可能性</td></tr><tr><td>7</td><td>QR開放中</td><td>読込待ち・誤開放を確認</td></tr></tbody></table><h2 id="_6-14-レジ横端末として使う" tabindex="-1">6-14. レジ横端末として使う <a class="header-anchor" href="#_6-14-レジ横端末として使う" aria-label="Permalink to &quot;6-14. レジ横端末として使う&quot;">​</a></h2><table tabindex="0"><thead><tr><th>場面</th><th>使い方</th></tr></thead><tbody><tr><td>会計待ち確認</td><td>レジ担当がどの卓を会計するか見る</td></tr><tr><td>清掃待ち確認</td><td>会計後、ホールへ片付けを依頼</td></tr><tr><td>未送信確認</td><td>レジ横で通信状況を確認</td></tr><tr><td>呼び出し補助</td><td>レジ担当がホールへ声かけ</td></tr></tbody></table><p>レジ横モードでは、壁掛けと同じく細かい卓操作は減らし、会計・清掃に必要な情報を見やすくします。</p><h2 id="_6-15-トラブルシューティング" tabindex="-1">6-15. トラブルシューティング <a class="header-anchor" href="#_6-15-トラブルシューティング" aria-label="Permalink to &quot;6-15. トラブルシューティング&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>QRを開放したのにお客様が注文画面に進めない</td><td>QRの有効期限切れ、別卓QR、通信不安定</td><td>運用タブでQR開放中か確認し、必要ならQR再発行</td></tr><tr><td>間違った卓をQR開放した</td><td>卓選択ミス</td><td>すぐにQR取消</td></tr><tr><td>会計待ちにした後に追加注文したい</td><td>会計待ち中は追加注文停止</td><td>会計解除して食事中へ戻す</td></tr><tr><td>料理完成が放置される</td><td>ホールが気づいていない</td><td>壁掛け端末を運用タブ、音ONで使う</td></tr><tr><td>通知音が鳴らない</td><td>音OFF、ブラウザの自動再生制限、端末音量ゼロ</td><td>音ONを押す、端末音量、マナーモードを確認</td></tr><tr><td>未送信が残る</td><td>通信障害、APIエラー</td><td>中身を確認し、KDSに重複がなければ再送</td></tr><tr><td>注文が二重に入った</td><td>再送前に別端末で入れ直した</td><td>注文履歴で片方を取消し、理由を残す</td></tr><tr><td>席移動できない</td><td>移動先が使用中、QR開放中</td><td>空席を選ぶ。必要ならQR取消</td></tr><tr><td>配膳完了を押し間違えた</td><td>操作ミス</td><td>運用ログまたは注文履歴から配膳取消</td></tr><tr><td>前のお客様のURLで画面が見える</td><td>セッション終了漏れの可能性</td><td>会計完了と清掃/終了状態を確認。次回QRは必ず再開放</td></tr></tbody></table><h2 id="_6-16-現場運用ルールの推奨" tabindex="-1">6-16. 現場運用ルールの推奨 <a class="header-anchor" href="#_6-16-現場運用ルールの推奨" aria-label="Permalink to &quot;6-16. 現場運用ルールの推奨&quot;">​</a></h2><h3 id="_6-16-1-通常操作は増やさない" tabindex="-1">6-16-1. 通常操作は増やさない <a class="header-anchor" href="#_6-16-1-通常操作は増やさない" aria-label="Permalink to &quot;6-16-1. 通常操作は増やさない&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>理由</th></tr></thead><tbody><tr><td>QR開放</td><td>来店時に毎回必要</td></tr><tr><td>注文入力</td><td>通常業務</td></tr><tr><td>呼び出し対応済み</td><td>回転を止めない</td></tr><tr><td>配膳完了</td><td>通常業務</td></tr><tr><td>会計待ち</td><td>通常業務</td></tr><tr><td>清掃完了</td><td>通常業務</td></tr></tbody></table><h3 id="_6-16-2-理由を残す操作" tabindex="-1">6-16-2. 理由を残す操作 <a class="header-anchor" href="#_6-16-2-理由を残す操作" aria-label="Permalink to &quot;6-16-2. 理由を残す操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>理由が必要な理由</th></tr></thead><tbody><tr><td>注文取消</td><td>売上・厨房・会計に影響する</td></tr><tr><td>品目取消</td><td>商品単位で会計額が変わる</td></tr><tr><td>数量変更</td><td>会計額と厨房作業に影響する</td></tr><tr><td>配膳取消</td><td>KDSとホールの状態を戻す</td></tr></tbody></table><h3 id="_6-16-3-店長に確認する操作" tabindex="-1">6-16-3. 店長に確認する操作 <a class="header-anchor" href="#_6-16-3-店長に確認する操作" aria-label="Permalink to &quot;6-16-3. 店長に確認する操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>理由</th></tr></thead><tbody><tr><td>調理後の取消</td><td>原価・廃棄・クレーム対応に影響</td></tr><tr><td>会計後の修正</td><td>売上とレジ締めに影響</td></tr><tr><td>大幅な数量変更</td><td>不正・入力ミスの可能性</td></tr><tr><td>席移動後の会計差異</td><td>注文の紐付け確認が必要</td></tr></tbody></table><h2 id="_6-17-システムが内部で行うこと" tabindex="-1">6-17. システムが内部で行うこと <a class="header-anchor" href="#_6-17-システムが内部で行うこと" aria-label="Permalink to &quot;6-17. システムが内部で行うこと&quot;">​</a></h2><table tabindex="0"><thead><tr><th>処理</th><th>内容</th></tr></thead><tbody><tr><td>店舗境界</td><td>ログインユーザーがアクセスできる店舗だけ操作可能</td></tr><tr><td>QR開放端末</td><td>どのデバイスアカウントでQRを開放したか保存</td></tr><tr><td>QR残り時間</td><td>有効期限までの秒数を表示</td></tr><tr><td>会計待ち解除</td><td>誤って会計待ちにした卓を食事中へ戻す</td></tr><tr><td>席移動</td><td>セッション、注文、QR、メモ、呼び出し、サブセッションを移動</td></tr><tr><td>取消ログ</td><td>注文取消、品目取消、数量変更、理由、操作端末を保存</td></tr><tr><td>配膳ログ</td><td>配膳完了、配膳取消、操作端末を保存</td></tr><tr><td>端末設定</td><td>端末ごとの表示モード、通知音、再通知間隔を保存</td></tr><tr><td>未送信復旧</td><td>通信失敗時、端末内に注文を保持</td></tr><tr><td>二重送信抑止</td><td>注文送信時に再送用キーを付与</td></tr><tr><td>会計後セッション終了</td><td>会計済み/終了済みセッションのURL再利用を防止</td></tr></tbody></table>',162)])])}const _=d(l,[["render",o]]);export{u as __pageData,_ as default};
